/**
 * Forward Natural-Earth-1 projection, identical to the d3-geo projection used
 * to generate WORLD_PATH/COUNTRY_XY (verified to <1e-13 px). Lets the widget
 * plot exact GeoIP coordinates (lon/lat) into the same viewBox without a
 * runtime d3 dependency.
 */
const NE1_K = 162.79151233333576
const NE1_TX = 500
const NE1_TY = 236.44689828074647

export function projectNE1(lon: number, lat: number): [number, number] {
  const l = (lon * Math.PI) / 180
  const p = (lat * Math.PI) / 180
  const p2 = p * p
  const p4 = p2 * p2
  const x = l * (0.8707 - 0.131979 * p2 + p4 * (-0.013791 + p4 * (0.003971 * p2 - 0.001529 * p4)))
  const y = p * (1.007226 + p2 * (0.015085 + p4 * (-0.044475 + 0.028874 * p2 - 0.005916 * p4)))
  return [NE1_K * x + NE1_TX, NE1_TY - NE1_K * y]
}
